UPDATE course_record
SET
course_rest_time = course_rest_time - #{totalCount},
id = LAST_INSERT_ID(id)
WHERE
course_id = #{cr.courseId}
AND student_id = #{cr.studentId}
AND course_rest_time >= #{totalCount}



    SELECT LAST_INSERT_ID()

mapper.select:
SELECT cr.*, s.student_name AS stuName FROM course_record cr LEFT JOIN student s ON cr.student_id = s.id
INNER JOIN permission_record pr ON cr.id = pr.course_record_id
cr.is_delete = 0
AND pr.user_id = #{dto.userId}
AND cr.id = #{dto.id}
AND cr.course_status = #{dto.courseStatus}
AND (
OR s.student_name LIKE CONCAT('%', #{dto.stuName}, '%')
OR cr.course_name LIKE CONCAT('%', #{dto.courseName}, '%')
OR cr.course_remark LIKE CONCAT('%', #{dto.courseRemark}, '%')
)
ORDER BY cr.update_time DESC, cr.id DESC
